+++ b/ext/date/php_date.c
@@ -2274,11 +2274,18 @@ static void update_errors_warnings(timelib_error_container **last_errors) /* {{{
 		return;
 	}

-	if ((*last_errors)->warning_count || (*last_errors)->error_count) {
-		DATEG(last_errors) = *last_errors;
+	char has_diagnostics = ((*last_errors)->warning_count || (*last_errors)->error_count);
+
+	if (DATEG(last_errors)) {
+		timelib_error_container_dtor(DATEG(last_errors));
+		DATEG(last_errors) = NULL;
 	}

-	timelib_error_container_dtor(*last_errors);
+	if (has_diagnostics) {
+		DATEG(last_errors) = *last_errors;
+	} else {
+		timelib_error_container_dtor(*last_errors);
+	}
 	*last_errors = NULL;
 } /* }}} */

